import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const MicrophoneIcon = () => (
    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M19 10v2a7 7 0 0 1-14 0v-2M12 19v4M8 23h8" />
    </svg>
);

const BellIcon = () => (
    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V4a2 2 0 10-4 0v1.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
    </svg>
);

const MenuIcon = () => (
    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M4 6h16M4 12h16M4 18h16" />
    </svg>
);

const pageLabels = {
    '/dashboard': 'Dashboard',
    '/practice': 'Speech Practice',
    '/interview': 'Interview Mode',
    '/gd': 'Group Discussion',
    '/personality': 'Personality Module',
};

export default function Navbar({ onMenuClick }) {
    const { user, logout } = useAuth();
    const navigate = useNavigate();
    const location = useLocation();
    const [dropOpen, setDropOpen] = useState(false);

    const pageTitle = pageLabels[location.pathname] || 'UnMute';

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const initials = user?.name
        ? user.name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2)
        : 'U';

    return (
        <header className="sticky top-0 z-30 h-16 flex items-center justify-between px-4 md:px-6
                       bg-dark-800/80 backdrop-blur-lg border-b border-white/5">
            {/* Left */}
            <div className="flex items-center gap-4">
                {/* Hamburger (mobile only) */}
                <button
                    onClick={onMenuClick}
                    className="md:hidden text-white/60 hover:text-white transition-colors p-1"
                    aria-label="Open menu"
                >
                    <MenuIcon />
                </button>

                {/* Logo (hidden on md+ since sidebar shows it) */}
                <Link to="/dashboard" className="flex items-center gap-2 md:hidden">
                    <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-primary-500 to-accent-500
                          flex items-center justify-center shadow-neon-blue">
                        <MicrophoneIcon />
                    </div>
                    <span className="font-display font-bold text-white text-base tracking-tight">UnMute</span>
                </Link>

                {/* Breadcrumb (desktop) */}
                <div className="hidden md:block">
                    <h1 className="text-white font-semibold text-base">{pageTitle}</h1>
                    <p className="text-white/40 text-xs">UnMute Platform</p>
                </div>
            </div>

            {/* Right */}
            <div className="flex items-center gap-3">
                {/* XP Badge */}
                {user?.xp !== undefined && (
                    <div className="hidden sm:flex items-center gap-1.5 px-3 py-1.5 rounded-full
                          bg-neon-yellow/10 border border-neon-yellow/20">
                        <span className="text-neon-yellow text-xs font-bold">⚡</span>
                        <span className="text-neon-yellow text-xs font-semibold">{user.xp || 0} XP</span>
                    </div>
                )}

                {/* Notification bell */}
                <button className="relative w-9 h-9 rounded-xl bg-white/5 hover:bg-white/10
                           flex items-center justify-center text-white/60 hover:text-white
                           transition-all duration-200">
                    <BellIcon />
                    <span className="absolute top-1.5 right-1.5 w-2 h-2 rounded-full bg-neon-pink" />
                </button>

                {/* Avatar dropdown */}
                <div className="relative">
                    <button
                        onClick={() => setDropOpen(p => !p)}
                        className="flex items-center gap-2 px-2 py-1.5 rounded-xl hover:bg-white/5
                       transition-all duration-200 group"
                    >
                        <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-primary-500 to-accent-500
                            flex items-center justify-center text-white text-xs font-bold
                            shadow-neon-purple">
                            {initials}
                        </div>
                        <div className="hidden sm:block text-left">
                            <p className="text-white text-xs font-semibold leading-tight">{user?.name || 'User'}</p>
                            <p className="text-white/40 text-[10px] leading-tight">
                                Level {user?.level || 1}
                            </p>
                        </div>
                        <svg className={`w-4 h-4 text-white/40 transition-transform duration-200 ${dropOpen ? 'rotate-180' : ''}`}
                            fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                            <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                        </svg>
                    </button>

                    {dropOpen && (
                        <div className="absolute right-0 top-full mt-2 w-48 glass-card shadow-card py-1 z-50
                            animate-fadeInUp">
                            <div className="px-3 py-2 border-b border-white/5">
                                <p className="text-white text-xs font-semibold">{user?.name}</p>
                                <p className="text-white/40 text-[11px]">{user?.email}</p>
                            </div>
                            <button
                                onClick={() => { setDropOpen(false); navigate('/personality'); }}
                                className="w-full text-left px-3 py-2 text-sm text-white/70 hover:text-white
                           hover:bg-white/5 transition-colors"
                            >
                                🎭 Personality Module
                            </button>
                            <button
                                onClick={() => { setDropOpen(false); handleLogout(); }}
                                className="w-full text-left px-3 py-2 text-sm text-red-400
                           hover:bg-red-500/10 transition-colors"
                            >
                                🚪 Sign Out
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </header>
    );
}
